def deserialize(s):
    if not s: return None
    if s[0] != '[':
        return {"val": int(s)}
    stack, curr_num, sign = [], 0, 1
    for i, c in enumerate(s):
        if c == '[':
            stack.append({"val": None, "list": []})
        elif c == '-': sign = -1
        elif c.isdigit(): curr_num = curr_num * 10 + int(c)
        elif c in ',]':
            if s[i-1].isdigit():
                stack[-1]["list"].append({"val": sign * curr_num})
            curr_num, sign = 0, 1
            if c == ']' and len(stack) > 1:
                nested = stack.pop()
                stack[-1]["list"].append(nested)
    return stack[0]

